SELECT ph.id,ph.post_id,ph.post_history_type_id,ph.creation_date,ph.revision_guid,p.post_title,p.score,u.id AS editor_id,u.display_name AS editor_name FROM post_history ph JOIN posts p ON p.id=ph.post_id LEFT JOIN users u ON u.id=ph.user_id WHERE ph.id=1894 AND ph.post_id=1679;
SELECT ph.id,ph.post_id,ph.post_history_type_id,ph.creation_date,p.post_title,u.display_name FROM post_history ph JOIN posts p ON p.id=ph.post_id LEFT JOIN users u ON u.id=ph.user_id WHERE ph.id=1894;
SELECT ph.id,ph.post_id,ph.post_history_type_id,ph.creation_date,ph.user_id,u.display_name,p.post_title FROM post_history ph JOIN posts p ON p.id=ph.post_id LEFT JOIN users u ON u.id=ph.user_id WHERE ph.post_id=1679 ORDER BY ph.creation_date DESC;
SELECT ph.id,ph.post_id,ph.post_history_type_id,ph.creation_date,p.post_title,u.display_name FROM post_history ph JOIN posts p ON p.id=ph.post_id LEFT JOIN users u ON u.id=ph.user_id WHERE (ph.id=1894 AND ph.post_id=1679) OR (ph.id=1418 AND ph.post_id=1240) OR (ph.id=2990 AND ph.post_id=2605) OR (ph.id=2671 AND ph.post_id=2332) ORDER BY ph.id;
SELECT ph.id,ph.post_id,ph.post_history_type_id,ph.creation_date,p.post_title,u.display_name FROM post_history ph JOIN posts p ON p.id=ph.post_id LEFT JOIN users u ON u.id=ph.user_id WHERE ph.id>=1400 AND ph.id<3001 ORDER BY ph.id LIMIT 500;
SELECT u.id,u.display_name,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count,MIN(ph.creation_date) AS first_revision,MAX(ph.creation_date) AS last_revision FROM post_history ph JOIN users u ON u.id=ph.user_id WHERE ph.user_id=1 GROUP BY u.id,u.display_name;
SELECT p.id,p.post_title,ph.post_history_type_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count,MIN(ph.creation_date) AS first_revision,MAX(ph.creation_date) AS last_revision FROM post_history ph JOIN posts p ON p.id=ph.post_id WHERE ph.post_id=1679 GROUP BY p.id,p.post_title,ph.post_history_type_id ORDER BY revision_count DESC;
SELECT DATE(ph.creation_date) AS revision_day,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.user_id) AS active_editors FROM post_history ph WHERE ph.creation_date>='2009-04-01' AND ph.creation_date<'2009-07-01' GROUP BY DATE(ph.creation_date) ORDER BY revision_day;
SELECT p.id,p.post_title,p.score,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count,MAX(ph.creation_date) AS last_revision FROM posts p JOIN post_history ph ON ph.post_id=p.id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' AND p.post_type_id=1 GROUP BY p.id,p.post_title,p.score HAVING COUNT(ph.id)>=2 ORDER BY revision_count DESC LIMIT 100;
SELECT u.id,u.display_name,u.reputation,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count FROM posts p JOIN post_history ph ON ph.post_id=p.id JOIN users u ON u.id=ph.user_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' GROUP BY u.id,u.display_name,u.reputation HAVING COUNT(ph.id)>=3 ORDER BY revision_count DESC,edited_posts DESC LIMIT 100;
SELECT owner.id AS owner_id,owner.display_name AS owner_name,editor.id AS editor_id,editor.display_name AS editor_name,COUNT(ph.id) AS revision_count,COUNT(DISTINCT p.id) AS edited_posts FROM posts p JOIN post_history ph ON ph.post_id=p.id LEFT JOIN users owner ON owner.id=p.owner_user_id LEFT JOIN users editor ON editor.id=ph.user_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' GROUP BY owner.id,owner.display_name,editor.id,editor.display_name HAVING COUNT(ph.id)>=3 ORDER BY revision_count DESC LIMIT 100;
SELECT u.id,u.display_name,COUNT(ph.id) AS own_revision_count,COUNT(DISTINCT p.id) AS own_edited_posts,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count FROM posts p JOIN post_history ph ON ph.post_id=p.id AND ph.user_id=p.owner_user_id JOIN users u ON u.id=p.owner_user_id WHERE p.creation_date>='2009-01-01' AND p.creation_date<'2010-01-01' GROUP BY u.id,u.display_name ORDER BY own_revision_count DESC LIMIT 100;
WITH ranked_history AS (SELECT ph.id,ph.post_id,ph.user_id,ph.post_history_type_id,ph.creation_date,ROW_NUMBER() OVER (PARTITION BY ph.post_id ORDER BY ph.creation_date DESC,ph.id DESC) AS rn FROM post_history ph JOIN posts p ON p.id=ph.post_id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01') SELECT rh.id,rh.post_id,p.post_title,rh.post_history_type_id,rh.creation_date,u.display_name FROM ranked_history rh JOIN posts p ON p.id=rh.post_id LEFT JOIN users u ON u.id=rh.user_id WHERE rh.rn=1 ORDER BY rh.creation_date DESC LIMIT 100;
WITH history_stats AS (SELECT p.id,p.post_title,p.owner_user_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count FROM posts p JOIN post_history ph ON ph.post_id=p.id WHERE p.creation_date>='2009-04-01' AND p.creation_date<'2009-07-01' GROUP BY p.id,p.post_title,p.owner_user_id) SELECT hs.id,hs.post_title,u.display_name,hs.revision_count,hs.editor_count,hs.history_type_count,DENSE_RANK() OVER (ORDER BY hs.revision_count DESC) AS revision_rank FROM history_stats hs LEFT JOIN users u ON u.id=hs.owner_user_id ORDER BY revision_rank LIMIT 100;
WITH question_history AS (SELECT ph.post_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count FROM post_history ph GROUP BY ph.post_id),answer_history AS (SELECT ph.post_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count FROM post_history ph GROUP BY ph.post_id) SELECT q.id AS question_id,q.post_title,a.id AS answer_id,qh.revision_count AS question_revisions,qh.editor_count AS question_editors,ah.revision_count AS answer_revisions,ah.editor_count AS answer_editors FROM posts q JOIN posts a ON a.id=q.accepted_answer_id LEFT JOIN question_history qh ON qh.post_id=q.id LEFT JOIN answer_history ah ON ah.post_id=a.id WHERE q.creation_date>='2009-04-01' AND q.creation_date<'2009-07-01' AND q.post_type_id=1 ORDER BY COALESCE(qh.revision_count,0)+COALESCE(ah.revision_count,0) DESC LIMIT 100;
WITH selected_history AS (SELECT id,post_id,user_id,post_history_type_id,creation_date FROM post_history WHERE (id=1894 AND post_id=1679) OR (id=1418 AND post_id=1240) OR (id=2990 AND post_id=2605) OR (id=2671 AND post_id=2332) OR (id=2620 AND post_id=2298) OR (id=1427 AND post_id=1265) OR (id=2497 AND post_id=2183) OR (id=1661 AND post_id=1474)) SELECT sh.id,sh.post_id,sh.post_history_type_id,sh.creation_date,p.post_title,p.score,u.display_name FROM selected_history sh JOIN posts p ON p.id=sh.post_id LEFT JOIN users u ON u.id=sh.user_id ORDER BY sh.id;
WITH selected_posts AS (SELECT DISTINCT ph.post_id FROM post_history ph WHERE (ph.id=1894 AND ph.post_id=1679) OR (ph.id=1418 AND ph.post_id=1240) OR (ph.id=2990 AND ph.post_id=2605) OR (ph.id=2671 AND ph.post_id=2332)),history_stats AS (SELECT ph.post_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.user_id) AS editor_count FROM post_history ph JOIN selected_posts sp ON sp.post_id=ph.post_id GROUP BY ph.post_id),comment_stats AS (SELECT c.post_id,COUNT(c.id) AS comment_count,COUNT(DISTINCT c.user_id) AS commenter_count FROM comments c JOIN selected_posts sp ON sp.post_id=c.post_id GROUP BY c.post_id) SELECT p.id,p.post_title,hs.revision_count,hs.editor_count,cs.comment_count,cs.commenter_count FROM selected_posts sp JOIN posts p ON p.id=sp.post_id LEFT JOIN history_stats hs ON hs.post_id=sp.post_id LEFT JOIN comment_stats cs ON cs.post_id=sp.post_id;
WITH selected_posts AS (SELECT DISTINCT ph.post_id FROM post_history ph WHERE (ph.id=1894 AND ph.post_id=1679) OR (ph.id=1418 AND ph.post_id=1240) OR (ph.id=2990 AND ph.post_id=2605) OR (ph.id=2671 AND ph.post_id=2332) OR (ph.id=2620 AND ph.post_id=2298) OR (ph.id=1427 AND ph.post_id=1265) OR (ph.id=2497 AND ph.post_id=2183) OR (ph.id=1661 AND ph.post_id=1474)),history_stats AS (SELECT ph.post_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count FROM post_history ph JOIN selected_posts sp ON sp.post_id=ph.post_id GROUP BY ph.post_id),vote_stats AS (SELECT v.post_id,COUNT(v.id) AS vote_count,COUNT(DISTINCT v.vote_type_id) AS vote_type_count FROM votes v JOIN selected_posts sp ON sp.post_id=v.post_id GROUP BY v.post_id) SELECT p.id,p.post_title,hs.revision_count,hs.history_type_count,vs.vote_count,vs.vote_type_count FROM selected_posts sp JOIN posts p ON p.id=sp.post_id LEFT JOIN history_stats hs ON hs.post_id=sp.post_id LEFT JOIN vote_stats vs ON vs.post_id=sp.post_id ORDER BY p.id;
SELECT YEAR(ph.creation_date) AS year_number,MONTH(ph.creation_date) AS month_number,p.post_type_id,ph.post_history_type_id,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.user_id) AS active_editors FROM post_history ph JOIN posts p ON p.id=ph.post_id WHERE ph.creation_date>='2009-01-01' AND ph.creation_date<'2010-01-01' GROUP BY YEAR(ph.creation_date),MONTH(ph.creation_date),p.post_type_id,ph.post_history_type_id ORDER BY year_number,month_number,p.post_type_id,ph.post_history_type_id;
SELECT u.id,u.display_name,COUNT(ph.id) AS revision_count,COUNT(DISTINCT ph.post_id) AS edited_posts,COUNT(DISTINCT ph.post_history_type_id) AS history_type_count,MIN(ph.creation_date) AS first_revision,MAX(ph.creation_date) AS last_revision FROM post_history ph JOIN users u ON u.id=ph.user_id GROUP BY u.id,u.display_name HAVING COUNT(ph.id)>=10 ORDER BY revision_count DESC LIMIT 100;